const pollMs = 100;
const attackCooldownMs = 600;
const hostileNames = new Set(['zombie', 'skeleton', 'husk', 'drowned', 'stray', 'spider', 'creeper', 'baby_zombie', 'piglin', 'enderman']);
const normalize = function (val) {
  return String(val).trim().toLowerCase().replace(/^minecraft:/, '').replace(/\\s+/g, '_');
};
const findNearestHostile = function () {
  const hostiles = Object.values(bot.entities).filter(function (e) {
    return e && e.isValid && e.type === 'hostile' || (e && hostileNames.has(e.name));
  });
  let nearest = null;
  let minDist = Infinity;
  for (const h of hostiles) {
    const d = bot.entity.position.distanceTo(h.position);
    if (d < minDist) {
      minDist = d;
      nearest = h;
    }
  }
  return nearest;
};
if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is not alive.';
}
const targetName = normalize(args.weaponName);
const sword = bot.inventory.items().find(function (i) {
  return normalize(i.name) === targetName || normalize(i.displayName) === targetName;
});
if (!sword) {
  return '<NO ITEM>: Could not find ' + args.weaponName + ' in inventory.';
}
startBackgroundSkill(bot, 'kite_nearest_hostile', async function (token) {
  let lastAttackTime = 0;
  const startTime = Date.now();
  const movements = new Movements(bot);
  movements.canDig = false;
  bot.pathfinder.setMovements(movements);
  try {
    while (canContinueBotAction(bot, token)) {
      if (Date.now() - startTime >= args.maxDurationMs) break;
      const target = findNearestHostile();
      if (!target) {
        if (!await waitForActiveMs(bot, token, pollMs)) return;
        continue;
      }
      await bot.equip(sword, 'hand');
      const dist = bot.entity.position.distanceTo(target.position);
      const now = Date.now();
      if (dist < 4 && now - lastAttackTime > attackCooldownMs) {
        await bot.lookAt(target.position.offset(0, target.height || 1.6, 0), true);
        bot.attack(target);
        lastAttackTime = now;
      }
      if (dist < args.preferredDistance) {
        const diff = bot.entity.position.minus(target.position);
        if (diff.norm() > 0) {
          const retreatDir = diff.normalize().scale(args.retreatBlocks);
          const retreatPos = bot.entity.position.plus(retreatDir);
          bot.pathfinder.setGoal(new goals.GoalNear(retreatPos.x, retreatPos.y, retreatPos.z, 1));
        }
      } else {
        bot.pathfinder.stop();
      }
      if (!await waitForActiveMs(bot, token, pollMs)) return;
    }
  } finally {
    bot.pathfinder.setGoal(null);
    bot.clearControlStates();
  }
});
return '<STARTED>: Kiting nearest hostiles with ' + args.weaponName + ' for up to ' + args.maxDurationMs + 'ms.';

