startBackgroundSkill(bot, 'build_defensive_pillar', async function (token) {
  const pollMs = 50;
  const jumpWaitMs = 250;
  const startTime = Date.now();
  try {
    if (!await waitUntilWorldActive(bot, token, pollMs)) return;
    await bot.equip(inventoryItem, 'hand');
    let blocksPlaced = 0;
    const startY = Math.floor(bot.entity.position.y);
    while (canContinueBotAction(bot, token) && blocksPlaced < args.height) {
      if (Date.now() - startTime > args.maxDurationMs) break;
      if (!await waitUntilWorldActive(bot, token, pollMs)) return;
      const referenceBlock = bot.blockAt(bot.entity.position.offset(0, -1, 0));
      if (!referenceBlock) break;
      bot.setControlState('jump', true);
      await waitForActiveMs(bot, token, jumpWaitMs, pollMs);
      if (!canContinueBotAction(bot, token)) return;
      try {
        await bot.lookAt(bot.entity.position.offset(0, -1, 0), true);
        await bot.placeBlock(referenceBlock, new Vec3(0, 1, 0));
        blocksPlaced++;
      } catch (err) {
        if (err.message.includes('No block has been placed')) {
        }
      }
      bot.setControlState('jump', false);
      await waitForActiveMs(bot, token, 150, pollMs);
      const currentY = Math.floor(bot.entity.position.y);
      if (currentY >= startY + args.height) break;
    }
  } finally {
    bot.setControlState('jump', false);
    bot.clearControlStates();
  }
});
