if (!bot.entity || bot.health <= 0) {
  return '<UNSAFE>: Bot is dead or missing entity state.';
}
const targetMobIDs = (args.mobIDs || []).map(id => String(id));
const candidateMobs = Object.values(bot.entities).filter(function (entity) {
  if (!entity || !entity.isValid || entity.id === bot.entity.id) return false;
  const isIncluded = targetMobIDs.includes(String(entity.id));
  const isHostile = entity.kind === 'Hostile mobs' || entity.type === 'hostile' || ['zombie', 'skeleton', 'creeper', 'spider', 'husk', 'drowned', 'witch', 'enderman', 'stray'].includes(entity.name);
  return isIncluded || isHostile;
});
candidateMobs.sort(function (a, b) {
  return a.position.distanceSquared(bot.entity.position) - b.position.distanceSquared(bot.entity.position);
});
const threats = candidateMobs.slice(0, 3);
if (threats.length === 0) {
  return '<STOPPED>: No nearby hostile mobs found to retreat from.';
}
let bestPoint = null;
let maxMinDistance = -1;
const samplingCount = 16;
const center = bot.entity.position;
for (let i = 0; i < samplingCount; i += 1) {
  const angle = (i / samplingCount) * Math.PI * 2;
  const candidate = center.offset(Math.cos(angle) * args.retreatDistance, 0, Math.sin(angle) * args.retreatDistance);
  let minDistanceToThreat = Infinity;
  for (const threat of threats) {
    const dist = candidate.distanceTo(threat.position);
    if (dist < minDistanceToThreat) minDistanceToThreat = dist;
  }
  if (minDistanceToThreat > maxMinDistance) {
    maxMinDistance = minDistanceToThreat;
    bestPoint = candidate;
  }
}
if (!bestPoint) {
  return '<INVALID>: Could not calculate a valid retreat coordinate.';
}
startBackgroundSkill(bot, 'safety_retreat', async function (token) {
  const pollMs = 100;
  const startTime = Date.now();
  const movements = new Movements(bot);
