      if (Date.now() - startTime > args.maxDurationMs) break;
      if (bot.pathfinder.isGoalSatisfied(goal)) break;
      await waitForActiveMs(bot, token, pollMs, pollMs);
    }
  } finally {
    bot.pathfinder.stop();
    bot.pathfinder.setGoal(null);
  }
});
return '<STARTED>: Moving to safety point ' + bestPoint.toArray().map(v => Math.floor(v)).join(',') + ' which is furthest from the ' + threats.length + ' nearest threats.';
